import Image from "next/image";
import Link from "next/link";
import { Pencil } from "lucide-react";
import { getMe } from "@/api_call/api";

export default async function ProfilePage() {
    const user = await getMe()

  return (
    <div className="max-w-6xl mx-auto p-6 grid grid-cols-12 gap-6">
      {/* Sidebar */}
      <div className="col-span-12 md:col-span-3 bg-white shadow rounded-xl p-5 h-fit">
        <div className="flex flex-col items-center text-center border-b pb-5">
          <Image
            src={user?.image}
            alt="user"
            width={120}
            height={120}
            className="rounded-lg object-cover"
          />

          <h2 className="mt-4 text-lg font-semibold text-gray-800">
            {user?.data?.name} 
          </h2>

          <p className="text-sm text-gray-500">{user.email}</p>
        </div>

        <div className="mt-5  space-y-3">
          <Link
            href="/profile/edit"
            className="block bg-[#01A49E] text-white px-4 py-2 rounded-lg text-sm border border-[#01A49E] hover:bg-gray-100 hover:text-black"
          >
            My Addresses
          </Link>

          <button className="w-full text-left mt-3 px-4 py-2 rounded-lg text-md font-semibold text-red-500 cursor-pointer">
            Logout
          </button>
        </div>
      </div>

      {/* Profile Details */}
      <div className="col-span-12 md:col-span-9 bg-white shadow rounded-xl p-6">
        <div className="flex items-center justify-between mb-6">
          <h1 className="text-2xl font-bold text-gray-800">
            Profile Information
          </h1>

          <Link
            href="/profile/edit"
            className="flex gap-3 items-center bg-cyan-500 text-white px-5 py-2 rounded-lg text-sm"
          >
                     <Pencil size={18} />    Edit 
          </Link>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div>
            <p className="text-sm text-gray-500">First Name</p>
            <h3 className="font-medium text-gray-800 mt-1">
              {user.firstName}
            </h3>
          </div>

          <div>
            <p className="text-sm text-gray-500">Last Name</p>
            <h3 className="font-medium text-gray-800 mt-1">
              {user.lastName}
            </h3>
          </div>

          <div>
            <p className="text-sm text-gray-500">Email Address</p>
            <h3 className="font-medium text-gray-800 mt-1">
              {user.email}
            </h3>
          </div>

          <div>
            <p className="text-sm text-gray-500">Phone Number</p>
            <h3 className="font-medium text-gray-800 mt-1">
              {user.phone}
            </h3>
          </div>
        </div>
      </div>
    </div>
  );
}
